/*
 This node calculates carbon footprints based on route details
*/
const routes = $items()[0].json.routes;
const preferences = $items()[0].json.preferences || {};

/**
 * Carbon emission factors per mode of transport (kg CO2 per km) - example values
 */
const carbonFactors = {
  flight: 0.255,
  train: 0.041,
  bus: 0.105,
  car: 0.192
};

function calculateRouteCarbon(route) {
  return route.segments.reduce((total, segment) => {
    const factor = carbonFactors[segment.mode.toLowerCase()] || 0.2;
    return total + segment.distanceKm * factor;
  }, 0);
}

const enrichedRoutes = routes.map(route => {
  const carbonFootprintKg = calculateRouteCarbon(route);
  const sustainabilityScore = 1 - Math.min(carbonFootprintKg / 1000, 1); // normalized score

  // Adjust score based on user preferences if provided (example: prefer trains)
  let adjustedScore = sustainabilityScore;
  if (preferences.preferredModes) {
    if (preferences.preferredModes.includes('train') && route.segments.some(seg => seg.mode.toLowerCase() === 'train')) {
      adjustedScore += 0.1;
    }
    if (preferences.avoidFlights && route.segments.some(seg => seg.mode.toLowerCase() === 'flight')) {
      adjustedScore -= 0.2;
    }
  }

  adjustedScore = Math.min(Math.max(adjustedScore, 0), 1);

  return {
    ...route,
    carbonFootprintKg,
    sustainabilityScore: adjustedScore
  };
});

return enrichedRoutes.map(route => ({ json: route }));

/*
 * Dynamically adjust routes based on sustainability scores and user preferences
 * Here, we filter or rank routes to optimize eco-friendliness
 */
const routes = $items();
const minScore = $json.preferences && $json.preferences.minimumSustainabilityScore ? $json.preferences.minimumSustainabilityScore : 0.5;

const filteredRoutes = routes.filter(route => route.json.sustainabilityScore >= minScore);

if (filteredRoutes.length === 0) {
  // If no route meets min score, fallback to best possible (highest score)
  const bestRoute = routes.sort((a,b) => b.json.sustainabilityScore - a.json.sustainabilityScore)[0];
  return [bestRoute];
}

// Optionally sort by sustainability score descending
filteredRoutes.sort((a,b) => b.json.sustainabilityScore - a.json.sustainabilityScore);

return filteredRoutes;

/*
 * Select recommended carbon offset options based on route's carbon footprint
 * Example logic: select offsets where offsetKg >= footprintKg or bundle several
 */
const route = $items()[0].json;
const carbonOffsets = $items()[1].json.offsets || [];

const neededOffset = route.carbonFootprintKg;

// Filter and sort offsets by price ascending
const suitableOffsets = carbonOffsets
  .filter(offset => offset.offsetKg >= neededOffset)
  .sort((a, b) => a.priceUSD - b.priceUSD);

// If none single offset covers, find combination (simple approach: select multiple smallest offsets)
let selectedOffsets = [];
if (suitableOffsets.length > 0) {
  selectedOffsets = [suitableOffsets[0]];
} else {
  let sumOffset = 0;
  selectedOffsets = [];
  const sortedByOffset = carbonOffsets.sort((a, b) => a.offsetKg - b.offsetKg);
  for (const offset of sortedByOffset) {
    selectedOffsets.push(offset);
    sumOffset += offset.offsetKg;
    if (sumOffset >= neededOffset) break;
  }
}

route.recommendedOffsets = selectedOffsets;

return [{ json: route }];

/*
 * Final formatting and filtering for output response
 */
const route = $json;

return [{
  json: {
    itinerary: {
      start: route.origin,
      end: route.destination,
      departureDate: route.departureDate,
      returnDate: route.returnDate,
      segments: route.segments
    },
    carbonFootprintKg: route.carbonFootprintKg,
    sustainabilityScore: route.sustainabilityScore,
    recommendedCarbonOffsets: route.recommendedOffsets
  }
}];
